void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;

    // Left to right linear gradient on white base
    vec3 colLeft = vec3(1.0, 1.0, 1.0);       // Pure white
    vec3 colRight = vec3(0.97, 0.97, 0.98);   // Very light blue-tinted white
    vec3 col = mix(colLeft, colRight, uv.x);

    fragColor = vec4(col, 1.0);
}

